fn main() {
    let mut text = String::new();
    io::stdin().read_to_string(&mut text).unwrap();
    let mut iter = text.split_whitespace();//.map(|x| x.parse::<i64>().unwrap());
    let n = iter.next().unwrap().parse::<i64>().unwrap();
    let s = iter.next().unwrap();
    let mut up = true;
    let mut down = true;
    let mut left = true;
    let mut right = true;
    for c in s.chars() {
        let d = c as i64 - '0' as i64;
        if d == 1 || d == 2 || d == 3 {
            up = false;
        }
        if d == 7 || d == 9 || d == 0 {
            down = false;
        }
        if d == 1 || d == 4 || d == 7 || d == 0 {
            left = false;
        }
        if d == 3 || d == 6 || d == 9 || d == 0 {
            right = false;
        }
    }
    println!("{}", if (up || down || left || right) {"NO"} else {"YES"});

}

